  ('aboriginal-c5fb3965-moex-00178', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '我國憲法增修條文涉及原住民或原住民族事務之部分，以下何者錯誤？', '["中央民意代表選舉", "保留地之增劃編", "發展語言及文化", "保障地位及政治參與"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00179', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '目前原住民名字可採行之註記方式，以下舉例何者錯誤？', '["劉文雄", "劉文雄 夷將•拔路兒", "劉文雄 Icyang•Parod", "夷將•拔路兒 Icyang•Parod"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00180', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民族基本法中與部落有關之規範，以下敘述何者錯誤？', '["部落指原住民於原住民族地區一定區域內，依傳統規範共同生活結合而成之團體，經中央原住民族 主管機關核定者", "部落之核定、組織、部落會議之組成、決議程序及其他相關事項之辦法，由中央原住民族主管機關 定之", "政府於原住民族地區，應依原住民族意願，回復原住民族部落及山川傳統名稱", "政府辦理公務人員特種考試原住民族考試，得於相關法令規定優先分發至該原住民族公務人員所屬 部落"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00181', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '關於族語能力認證之現行制度，以下敘述何者錯誤？', '["族語能力認證分為初級、中級、中高級、高級及優級", "族語能力認證得委託學校或民間團體辦理認證工作", "族語能力認證之參加者須為本國籍，不受族別及年齡之限制", "族語能力認證方式包括測驗、審查兩類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00182', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '為促進原住民就業，保障原住民工作權及經濟生活，以下敘述何者錯誤？', '["原住民族工作權保障法保障對象為居住於原住民族地區以外之都市原住民", "各級政府機關、公立學校及公營事業機構應依循比例進用原則僱用原住民", "政府應依原住民群體工作習性，輔導原住民設立各種性質之原住民合作社", "依政府採購法得標之廠商，於國內員工總人數逾一百人者，應於履約期間僱用原住民"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00183', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '以下何者不屬於原住民族傳統智慧創作保護條例所保護的範圍？', '["原住民族傳統之宗教祭儀", "原住民族傳統之舞蹈", "原住民族傳統之神話", "原住民族傳統之服飾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00184', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '關於劃編原住民保留地，以下敘述何者錯誤？', '["原則為針對原住民迄今仍使用之公有土地", "目的為輔導原住民宗教團體取得宗教建築設施使用土地權利", "因不可抗力或天然災害等因素致使用中斷，仍可例外劃編", "依水利法規定屬於尋常洪水位行水區域之土地，不得劃編"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00185', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '關於原住民民族別之認定，以下敘述何者錯誤？', '["原住民父母屬於不同民族別者，其子女之民族別，未成年時得由法定代理人協議", "父母僅一方為原住民，具有原住民身分之子女，從具原住民身分之父或母之民族別", "行政院核定新民族別時，已註記民族別之成年人得依個人意願申請變更為該民族別", "原住民女子與原住民男子之非婚生子女，未經生父認領者，從父或母之民族別"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00186', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '關於8月1日原住民族日之由來，以下敘述何者正確？', '["紀念我國修憲將山胞正名為原住民", "紀念我國立法通過原住民族基本法", "紀念聯合國通過原住民族權利宣言", "紀念聯合國成立原住民族常設論壇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00187', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民族教育法，以下敘述何者錯誤？', '["所謂民族教育，係指依原住民族文化特性，對原住民學生所實施之民族知識教育", "所謂一般教育，係指民族教育外，對原住民學生所實施之一般性質教育", "所謂原住民族學校，係指原住民學生達一定人數或比率之高級中等以下學校", "所謂原住民教育班，係指為原住民學生教育需要，於一般學校中開設之班級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
